import torch
from torch.optim import Adam
import copy


class EMAModel:
    """
    Exponential moving average of model parameters.
    Use the EMA model for sample generation and evaluation;
    train the live model with gradient updates.
    """

    def __init__(self, model: torch.nn.Module, decay: float = 0.999):
        self.decay   = decay
        self.shadow  = copy.deepcopy(model)
        self.shadow.eval()

    @torch.no_grad()
    def update(self, model: torch.nn.Module) -> None:
        for s_param, param in zip(self.shadow.parameters(),
                                   model.parameters()):
            s_param.data.mul_(self.decay).add_(param.data, alpha=1 - self.decay)

    def generate(self, z: torch.Tensor) -> torch.Tensor:
        with torch.no_grad():
            return torch.sigmoid(self.shadow.decoder(z))  # or self.shadow(z)


# Usage in training loop
